solution: ```class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int n = s.length();
        int maxLen = 1;
        for (int l = 0; l < n; ++l) {
            int pairs = 0;
            for (int r = l + 1; r < n; ++r) {
                if (s.charAt(r) == s.charAt(r - 1)) {
                    pairs++;
                    if (pairs > 1) break;
                }
                maxLen = Math.max(maxLen, r - l + 1);
            }
        }
        return maxLen;
    }
}
